import fs from 'fs/promises';
import path from 'path';
export class McpGenerator {
    outDir;
    opts;
    constructor(outDir, opts = {}) {
        this.outDir = outDir;
        this.opts = opts;
    }
    async generate(tools) {
        await fs.mkdir(this.outDir, { recursive: true });
        const write = async (name, content) => {
            await fs.writeFile(path.join(this.outDir, name), content, 'utf-8');
        };
        await write('package.json', this._packageJson());
        await write('tsconfig.json', this._tsConfig());
        await write('schemas.ts', this._renderSchemas(tools));
        await write('tools.ts', this._renderTools(tools));
        await write('handlers.ts', this._renderHandlers(tools));
        await write('server.ts', this._renderServer(tools));
        await write('AGENTS.md', this._renderAgentsMd(tools));
        await this._validateGenerated(['tools.ts', 'handlers.ts', 'server.ts']);
    }
    async _validateGenerated(files) {
        for (const file of files) {
            const filePath = path.join(this.outDir, file);
            const content = await fs.readFile(filePath, 'utf-8');
            const lines = content.split('\n');
            for (let i = 0; i < lines.length; i++) {
                const line = lines[i];
                // Strip string/template literals before checking
                const stripped = line.replace(/"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*'|`(?:[^`\\]|\\.)*`/g, '""');
                // Check for invalid JS identifiers (hyphens in variable/function names)
                const badIdent = stripped.match(/\b(?:const|function|async function)\s+([a-zA-Z0-9_$]*-[a-zA-Z0-9_$-]*)\b/);
                if (badIdent) {
                    throw new Error(`Invalid JS identifier in ${file} line ${i + 1}: "${badIdent[1]}" - contains hyphen`);
                }
                // Check for non-ASCII outside string literals
                if (/[^\x00-\x7F]/.test(stripped)) {
                    throw new Error(`Non-ASCII character in ${file} line ${i + 1}: ${line.trim()}`);
                }
            }
        }
    }
    _packageJson() {
        return JSON.stringify({
            name: '@agentify/generated-server',
            version: '1.0.0',
            type: 'module',
            scripts: {
                build: 'tsc',
                start: 'node dist/server.js',
                mcp: 'tsx server.ts',
            },
            dependencies: {
                '@modelcontextprotocol/sdk': '^1.25.2',
                zod: '^3.22.0',
            },
            devDependencies: {
                typescript: '^5.4.0',
                tsx: '^4.19.0',
                '@types/node': '^20.0.0',
            },
        }, null, 2) + '\n';
    }
    _tsConfig() {
        return JSON.stringify({
            compilerOptions: {
                target: 'ES2022',
                module: 'ES2022',
                moduleResolution: 'Node',
                strict: true,
                outDir: 'dist',
                declaration: true,
                skipLibCheck: true,
                esModuleInterop: true,
            },
            include: ['./**/*.ts'],
            exclude: ['node_modules', 'dist'],
        }, null, 2) + '\n';
    }
    _renderSchemas(tools) {
        const imports = `import { z } from 'zod';\n\n`;
        const schemas = tools.map(t => {
            const props = t.params.map((p, i) => {
                const type = t.paramTypes[i] ?? 'string';
                const zodType = type === 'number' ? 'z.number()' :
                    type === 'boolean' ? 'z.boolean()' :
                        type === 'array' ? 'z.array(z.unknown())' :
                            type === 'object' ? 'z.record(z.unknown())' :
                                'z.string()';
                return `  ${p}: ${zodType}.optional()`;
            }).join(',\n');
            return `export const ${this._toVarName(t.name)}Schema = z.object({\n${props || '  // no parameters'}\n});`;
        }).join('\n\n');
        return imports + schemas + '\n';
    }
    _toVarName(name) {
        return name.replace(/[^a-zA-Z0-9_$]/g, '_');
    }
    _renderTools(tools) {
        const header = `// Auto-generated by Agentify - do not edit manually.\n\n`;
        const defs = tools.map(t => {
            const varName = this._toVarName(t.name);
            const props = t.params.map((p, i) => {
                const type = t.paramTypes[i] ?? 'string';
                return `        ${p}: { type: '${type}' as const, description: '${p}' }`;
            }).join(',\n');
            return `export const ${varName}Tool = {
  name:        '${t.name}',
  description: ${JSON.stringify(t.description)},
  service:     '${t.service}',
  inputSchema: {
    type: 'object' as const,
    properties: {
${props || '        // no parameters'}
    },
    required: [] as string[],
  },
};`;
        }).join('\n\n');
        const allTools = `\nexport const ALL_TOOLS = [\n${tools.map(t => `  ${this._toVarName(t.name)}Tool`).join(',\n')}\n];\n`;
        return header + defs + '\n' + allTools;
    }
    _renderHandlers(tools) {
        const apiDefs = Object.fromEntries(tools.map(t => [t.name, { method: t.httpMethod, path: t.httpPath }]));
        const header = `// Auto-generated by Agentify - do not edit manually.\n\n`;
        const apiDefsConst = `const API_DEFS: Record<string, { method: string; path: string }> = ${JSON.stringify(apiDefs, null, 2)};\n\n`;
        const invoker = `async function invokeApiTool(name: string, args: Record<string, unknown>): Promise<unknown> {
  const def = API_DEFS[name];
  if (!def) throw new Error(\`No API definition for tool: \${name}\`);

  const baseUrl = process.env.AGENTIFY_BASE_URL;
  if (!baseUrl) {
    throw new Error('AGENTIFY_BASE_URL environment variable is not set.');
  }

  const pathParamNames = [...def.path.matchAll(/\\{([^}]+)\\}/g)].map(m => m[1]);
  const resolvedPath = def.path.replace(/\\{([^}]+)\\}/g, (_, key: string) => {
    const val = args[key];
    return val !== undefined ? encodeURIComponent(String(val)) : \`{\${key}}\`;
  });

  const bodyArgs = Object.fromEntries(
    Object.entries(args).filter(([k]) => !pathParamNames.includes(k))
  );

  const url = new URL(resolvedPath, baseUrl);
  if (def.method === 'GET') {
    for (const [k, v] of Object.entries(bodyArgs)) url.searchParams.set(k, String(v));
  }

  const headers: Record<string, string> = {};
  if (def.method !== 'GET') headers['content-type'] = 'application/json';
  // Static credentials baked in at generation time (override with env vars if set)
  const authBasic  = process.env.AGENTIFY_AUTH_BASIC  ?? ${this.opts.authBasic ? JSON.stringify(this.opts.authBasic) : 'undefined'};
  const apiKey     = process.env.AGENTIFY_APIKEY      ?? ${this.opts.apiKey ? JSON.stringify(this.opts.apiKey) : 'undefined'};
  if (authBasic) headers['Authorization'] = \`Basic \${authBasic}\`;
  if (apiKey)    headers['apikey'] = apiKey;

  const res = await fetch(url.toString(), {
    method:  def.method,
    headers: Object.keys(headers).length > 0 ? headers : undefined,
    body:    def.method !== 'GET' ? JSON.stringify(bodyArgs) : undefined,
  });

  const text = await res.text();
  let body: unknown = text;
  try { body = JSON.parse(text); } catch {}
  return { status: res.status, ok: res.ok, body };
}\n\n`;
        const handlers = tools.map(t => `export async function handle_${this._toVarName(t.name)}(args: Record<string, unknown>): Promise<unknown> {
  return invokeApiTool('${t.name}', args);
}`).join('\n\n');
        const registry = `\n\ntype Handler = (args: Record<string, unknown>) => Promise<unknown>;

export const TOOL_HANDLERS: Record<string, Handler> = {
${tools.map(t => `  '${t.name}': handle_${this._toVarName(t.name)}`).join(',\n')}
};\n`;
        return header + apiDefsConst + invoker + handlers + registry;
    }
    _renderServer(tools) {
        const services = [...new Set(tools.map(t => t.service))];
        return `#!/usr/bin/env node
// Auto-generated by Agentify - do not edit manually.
// Start: npm run mcp

import { Server }               from '@modelcontextprotocol/sdk/server/index.js';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from '@modelcontextprotocol/sdk/types.js';

import { ALL_TOOLS }    from './tools.js';
import { TOOL_HANDLERS } from './handlers.js';

const server = new Server(
  { name: 'agentify-generated', version: '1.0.0' },
  { capabilities: { tools: {} } }
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: ALL_TOOLS.map(t => ({
    name:        t.name,
    description: t.description,
    inputSchema: t.inputSchema,
  })),
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args = {} } = request.params;
  const handler = TOOL_HANDLERS[name];
  if (!handler) {
    return {
      content: [{ type: 'text' as const, text: \`Unknown tool: \${name}\` }],
      isError: true,
    };
  }
  try {
    const result = await handler(args as Record<string, unknown>);
    return {
      content: [{
        type: 'text' as const,
        text: typeof result === 'string' ? result : JSON.stringify(result, null, 2),
      }],
    };
  } catch (err: any) {
    return {
      content: [{ type: 'text' as const, text: \`Error: \${err.message}\` }],
      isError: true,
    };
  }
});

async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  process.stderr.write(\`[agentify] MCP server running — \${ALL_TOOLS.length} tools across ${services.length} service(s): ${services.join(', ')}\\n\`);
}

main().catch(err => {
  process.stderr.write(\`[agentify] Fatal: \${err.message}\\n\`);
  process.exit(1);
});
`;
    }
    _renderAgentsMd(tools) {
        const services = [...new Set(tools.map(t => t.service))];
        const byService = services.map(svc => {
            const svcTools = tools.filter(t => t.service === svc);
            const rows = svcTools.map(t => {
                const params = t.params.length > 0 ? t.params.join(', ') : '-';
                return `| \`${t.name}\` | \`${t.httpMethod} ${t.httpPath}\` | ${t.description} | ${params} |`;
            }).join('\n');
            return `### ${svc}\n\n| Tool | Endpoint | Description | Params |\n|---|---|---|---|\n${rows}`;
        }).join('\n\n');
        return `# AGENTS.md
> Auto-generated by Agentify. Re-run \`agentify generate\` to refresh.

## Overview

**${tools.length} tools** across **${services.length} service(s)**: ${services.join(', ')}

Set \`AGENTIFY_BASE_URL\` to your platform base URL before starting the server.

## Tools by Service

${byService}

## Connecting to Claude Code

Add to \`.mcp.json\` in your project root:

\`\`\`json
{
  "mcpServers": {
    "agentify": {
      "command": "npx",
      "args": ["-y", "tsx", "${this.outDir}/server.ts"],
      "env": {
        "AGENTIFY_BASE_URL": "http://your-platform:8080"
      }
    }
  }
}
\`\`\`
`;
    }
}
